import React, { useMemo } from 'react';
import {
  Box,
  Card,
  CardContent,
  TextField,
  Button,
  Typography,
  Grid,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TableFooter,
  Paper,
  Stack,
  Divider,
  Avatar,
  IconButton,
  Tooltip,
  Alert,
  InputAdornment,
  Chip,
  alpha,
  useTheme,
} from '@mui/material';
import {
  Person as PersonIcon,
  Delete as DeleteIcon,
  Calculate as CalculateIcon,
  Save as SaveIcon,
  TrendingUp as TrendingUpIcon,
  TrendingDown as TrendingDownIcon,
  AccountBalance as MoneyIcon,
  Summarize as SummarizeIcon,
} from '@mui/icons-material';
import { Controller } from 'react-hook-form';
import CallSSO from '../../utils/functions/CalSSO';

export default function AddSalaryTable({
  fields = [],
  control,
  watch,
  setValue,
  remove,
  onSubmit,
}) {
  const theme = useTheme();

  // เพิ่มการตรวจสอบที่ปลอดภัยมากขึ้น
  const watchedFields = watch ? watch('salaryData') : [];
  const safeWatchedFields = Array.isArray(watchedFields) ? watchedFields : [];

  // คำนวณเงินเดือนสุทธิสำหรับแต่ละแถว
  const calculateNetSalary = (index) => {
    if (!safeWatchedFields[index]) return 0;

    const field = safeWatchedFields[index];

    // รายได้
    const salary = parseFloat(field?.revenue?.salary || 0);
    const overtime = parseFloat(field?.revenue?.overtime || 0);
    const allowances = parseFloat(field?.revenue?.allowances || 0);
    const bonus = parseFloat(field?.revenue?.bonus || 0);

    // ค่าใช้จ่าย/การหัก
    const tax = parseFloat(field?.expenses?.tax || 0);
    const sso = parseFloat(field?.expenses?.sso || 0);
    const other = parseFloat(field?.expenses?.other || 0);

    const totalIncome = salary + overtime + allowances + bonus;
    const totalDeductions = tax + sso + other;

    return totalIncome - totalDeductions;
  };

  // คำนวณยอดรวมทั้งหมด
  const totalSummary = useMemo(() => {
    if (!safeWatchedFields || safeWatchedFields.length === 0) {
      return {
        totalSalary: 0,
        totalOvertime: 0,
        totalAllowances: 0,
        totalBonus: 0,
        totalIncome: 0,
        totalTax: 0,
        totalSSO: 0,
        totalOther: 0,
        totalDeductions: 0,
        totalNet: 0,
        totalWorkDays: 0,
      };
    }

    return safeWatchedFields.reduce(
      (summary, field, index) => {
        if (!field) return summary;

        // รายได้แต่ละประเภท
        const salary = parseFloat(field?.revenue?.salary || 0);
        const overtime = parseFloat(field?.revenue?.overtime || 0);
        const allowances = parseFloat(field?.revenue?.allowances || 0);
        const bonus = parseFloat(field?.revenue?.bonus || 0);

        // รายได้รวม
        const income = salary + overtime + allowances + bonus;

        // วันทำงาน
        const workDays = fields[index]?.totalWork || 0;

        // การหักแต่ละประเภท
        const tax = parseFloat(field?.expenses?.tax || 0);
        const sso = CallSSO(
          fields[index]?.employeeDetails?.salary?.month,
          watch('sso'),
        );
        const other = parseFloat(field?.expenses?.other || 0);

        // การหักรวม
        const deductions = tax + sso + other;

        // เงินสุทธิ
        const net = income - deductions;

        return {
          totalSalary: summary.totalSalary + salary,
          totalOvertime: summary.totalOvertime + overtime,
          totalAllowances: summary.totalAllowances + allowances,
          totalBonus: summary.totalBonus + bonus,
          totalIncome: summary.totalIncome + income,
          totalTax: summary.totalTax + tax,
          totalSSO: summary.totalSSO + sso,
          totalOther: summary.totalOther + other,
          totalDeductions: summary.totalDeductions + deductions,
          totalNet: summary.totalNet + net,
          totalWorkDays: summary.totalWorkDays + workDays,
        };
      },
      {
        totalSalary: 0,
        totalOvertime: 0,
        totalAllowances: 0,
        totalBonus: 0,
        totalIncome: 0,
        totalTax: 0,
        totalSSO: 0,
        totalOther: 0,
        totalDeductions: 0,
        totalNet: 0,
        totalWorkDays: 0,
      },
    );
  }, [safeWatchedFields, watch, fields]);

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('th-TH', {
      style: 'currency',
      currency: 'THB',
      minimumFractionDigits: 0,
    }).format(amount || 0);
  };

  const renderTableHeader = () => (
    <Box
      sx={{
        display: 'flex',
        justifyContent: 'space-between',
        mb: 3,
        alignItems: 'center',
      }}
    >
      <Typography variant="h6" component="h2">
        รายการเงินเดือนรายเดือน
      </Typography>
      <Button
        variant="contained"
        startIcon={<SaveIcon />}
        disabled={!Array.isArray(fields) || fields.length === 0}
        size="large"
        type="submit"
        sx={{ borderRadius: 2 }}
      >
        บันทึกข้อมูล
      </Button>
    </Box>
  );

  // ตรวจสอบว่า fields เป็น array และมีข้อมูลหรือไม่
  if (!Array.isArray(fields) || fields.length === 0) {
    return (
      <Card variant="outlined" sx={{ borderRadius: 2 }}>
        <CardContent sx={{ py: 6, textAlign: 'center' }}>
          <MoneyIcon sx={{ fontSize: 64, color: 'text.disabled', mb: 2 }} />
          <Typography variant="h6" color="text.secondary" gutterBottom>
            ไม่พบข้อมูลการลงเวลา
          </Typography>
          <Typography variant="body2" color="text.secondary">
            กรุณาเลือกช่วงวันที่ที่มีข้อมูลการลงเวลาของพนักงาน
          </Typography>
        </CardContent>
      </Card>
    );
  }

  return (
    <Box>
      {renderTableHeader()}

      <Card
        variant="outlined"
        sx={{ borderRadius: 2, overflow: 'hidden', mb: 3 }}
      >
        <Box
          sx={{
            display: 'flex',
            justifyContent: 'flex-end',
            p: 2,
            borderBottom: `1px solid ${alpha(theme.palette.divider, 0.5)}`,
          }}
        >
          <Stack direction="row" spacing={1} alignItems="center">
            <Typography variant="body2">ประกันสังคม</Typography>
            <Controller
              name={`sso`}
              control={control}
              defaultValue={5}
              render={({ field: controlField }) => (
                <TextField
                  {...controlField}
                  size="small"
                  type="number"
                  InputProps={{
                    endAdornment: (
                      <InputAdornment position="end">%</InputAdornment>
                    ),
                  }}
                  sx={{ width: 120 }}
                />
              )}
            />
          </Stack>
        </Box>
        <TableContainer>
          <Table sx={{ minWidth: 1200 }} size="small">
            <TableHead>
              <TableRow
                sx={{ bgcolor: alpha(theme.palette.primary.main, 0.05) }}
              >
                <TableCell sx={{ fontWeight: 600, minWidth: 200 }}>
                  พนักงาน
                </TableCell>
                <TableCell
                  align="center"
                  sx={{ fontWeight: 600, minWidth: 100 }}
                >
                  วันทำงาน
                </TableCell>
                <TableCell
                  align="center"
                  sx={{ fontWeight: 600, minWidth: 120 }}
                >
                  เงินเดือน
                </TableCell>
                <TableCell
                  align="center"
                  sx={{ fontWeight: 600, minWidth: 100 }}
                >
                  โอที
                </TableCell>
                <TableCell
                  align="center"
                  sx={{ fontWeight: 600, minWidth: 100 }}
                >
                  เบี้ยเลี้ยง
                </TableCell>
                <TableCell
                  align="center"
                  sx={{ fontWeight: 600, minWidth: 100 }}
                >
                  โบนัส
                </TableCell>
                <TableCell
                  align="center"
                  sx={{ fontWeight: 600, minWidth: 100 }}
                >
                  หักภาษี
                </TableCell>
                <TableCell
                  align="center"
                  sx={{ fontWeight: 600, minWidth: 120 }}
                >
                  ประกันสังคม
                </TableCell>
                <TableCell
                  align="center"
                  sx={{ fontWeight: 600, minWidth: 100 }}
                >
                  หักอื่นๆ
                </TableCell>
                <TableCell
                  align="center"
                  sx={{ fontWeight: 600, minWidth: 120 }}
                >
                  สุทธิ
                </TableCell>
                <TableCell
                  align="center"
                  sx={{ fontWeight: 600, minWidth: 80 }}
                >
                  จัดการ
                </TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {fields.map((field, index) => (
                <TableRow
                  key={field?.id || index}
                  sx={{
                    '&:hover': {
                      bgcolor: alpha(theme.palette.primary.main, 0.02),
                    },
                  }}
                >
                  <TableCell>
                    <Stack direction="row" spacing={2} alignItems="center">
                      <Box>
                        <Typography variant="body2" fontWeight={500}>
                          {field?.employeeDetails?.firstname || ''}{' '}
                          {field?.employeeDetails?.lastname || ''}
                        </Typography>
                        <Typography variant="caption" color="text.secondary">
                          {field?.employeeDetails?.department?.name || '-'} •{' '}
                          {field?.employeeDetails?.role?.name || '-'}
                        </Typography>
                      </Box>
                    </Stack>
                  </TableCell>

                  <TableCell align="center">
                    <Chip
                      label={`${field?.totalWork || 0} วัน`}
                      size="small"
                      color="primary"
                      variant="outlined"
                    />
                  </TableCell>

                  {/* เงินเดือนพื้นฐาน */}
                  <TableCell align="center">
                    {control ? (
                      <Controller
                        name={`salaryData.${index}.revenue.salary`}
                        control={control}
                        defaultValue={
                          field?.employeeDetails?.salary?.month || 0
                        }
                        render={({ field: controlField }) => (
                          <TextField
                            {...controlField}
                            size="small"
                            type="number"
                            InputProps={{
                              startAdornment: (
                                <InputAdornment position="start">
                                  ฿
                                </InputAdornment>
                              ),
                            }}
                            sx={{ width: 140 }}
                          />
                        )}
                      />
                    ) : (
                      <Typography variant="body2">
                        {formatCurrency(field?.baseSalary || 0)}
                      </Typography>
                    )}
                  </TableCell>

                  {/* โอที */}
                  <TableCell align="center">
                    {control ? (
                      <Controller
                        name={`salaryData.${index}.revenue.overtime`}
                        control={control}
                        defaultValue={0}
                        render={({ field: controlField }) => (
                          <TextField
                            {...controlField}
                            size="small"
                            type="number"
                            InputProps={{
                              startAdornment: (
                                <InputAdornment position="start">
                                  ฿
                                </InputAdornment>
                              ),
                            }}
                            sx={{ width: 120 }}
                          />
                        )}
                      />
                    ) : (
                      <Typography variant="body2">
                        {formatCurrency(field?.overtime || 0)}
                      </Typography>
                    )}
                  </TableCell>

                  {/* เบี้ยเลี้ยง */}
                  <TableCell align="center">
                    {control ? (
                      <Controller
                        name={`salaryData.${index}.revenue.allowances`}
                        control={control}
                        defaultValue={0}
                        render={({ field: controlField }) => (
                          <TextField
                            {...controlField}
                            size="small"
                            type="number"
                            InputProps={{
                              startAdornment: (
                                <InputAdornment position="start">
                                  ฿
                                </InputAdornment>
                              ),
                            }}
                            sx={{ width: 120 }}
                          />
                        )}
                      />
                    ) : (
                      <Typography variant="body2">
                        {formatCurrency(field?.allowances || 0)}
                      </Typography>
                    )}
                  </TableCell>

                  {/* โบนัส */}
                  <TableCell align="center">
                    {control ? (
                      <Controller
                        name={`salaryData.${index}.revenue.bonus`}
                        control={control}
                        defaultValue={0}
                        render={({ field: controlField }) => (
                          <TextField
                            {...controlField}
                            size="small"
                            type="number"
                            InputProps={{
                              startAdornment: (
                                <InputAdornment position="start">
                                  ฿
                                </InputAdornment>
                              ),
                            }}
                            sx={{ width: 120 }}
                          />
                        )}
                      />
                    ) : (
                      <Typography variant="body2">
                        {formatCurrency(field?.bonus || 0)}
                      </Typography>
                    )}
                  </TableCell>

                  {/* หักภาษี */}
                  <TableCell align="center">
                    {control ? (
                      <Controller
                        name={`salaryData.${index}.expenses.tax`}
                        control={control}
                        defaultValue={0}
                        render={({ field: controlField }) => (
                          <TextField
                            {...controlField}
                            size="small"
                            type="number"
                            InputProps={{
                              startAdornment: (
                                <InputAdornment position="start">
                                  ฿
                                </InputAdornment>
                              ),
                            }}
                            sx={{ width: 120 }}
                          />
                        )}
                      />
                    ) : (
                      <Typography variant="body2">
                        {formatCurrency(field?.withholdingTax || 0)}
                      </Typography>
                    )}
                  </TableCell>

                  {/* ประกันสังคม */}
                  <TableCell align="center">
                    <Paper
                      variant="outlined"
                      sx={{
                        p: 1,
                        bgcolor: alpha(theme.palette.grey[500], 0.05),
                        borderColor: alpha(theme.palette.grey[500], 0.2),
                      }}
                    >
                      <Typography variant="body2" fontWeight={500}>
                        {CallSSO(
                          field?.employeeDetails?.salary?.month,
                          watch('sso'),
                        )}
                      </Typography>
                    </Paper>
                  </TableCell>

                  {/* หักอื่นๆ */}
                  <TableCell align="center">
                    {control ? (
                      <Controller
                        name={`salaryData.${index}.expenses.other`}
                        control={control}
                        defaultValue={0}
                        render={({ field: controlField }) => (
                          <TextField
                            {...controlField}
                            size="small"
                            type="number"
                            InputProps={{
                              startAdornment: (
                                <InputAdornment position="start">
                                  ฿
                                </InputAdornment>
                              ),
                            }}
                            sx={{ width: 120 }}
                          />
                        )}
                      />
                    ) : (
                      <Typography variant="body2">
                        {formatCurrency(field?.otherDeductions || 0)}
                      </Typography>
                    )}
                  </TableCell>

                  {/* เงินเดือนสุทธิ */}
                  <TableCell align="center">
                    <Paper
                      variant="outlined"
                      sx={{
                        p: 1,
                        bgcolor: alpha(theme.palette.success.main, 0.05),
                        borderColor: alpha(theme.palette.success.main, 0.2),
                        minWidth: 100,
                      }}
                    >
                      <Typography
                        variant="body2"
                        fontWeight={600}
                        color="success.main"
                        textAlign="right"
                      >
                        {formatCurrency(calculateNetSalary(index))}
                      </Typography>
                    </Paper>
                  </TableCell>

                  {/* ปุ่มจัดการ */}
                  <TableCell align="center">
                    {remove && (
                      <Tooltip title="ลบรายการ">
                        <IconButton
                          size="small"
                          color="error"
                          onClick={() => remove(index)}
                          sx={{
                            '&:hover': {
                              bgcolor: alpha(theme.palette.error.main, 0.1),
                            },
                          }}
                        >
                          <DeleteIcon fontSize="small" />
                        </IconButton>
                      </Tooltip>
                    )}
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
            <TableFooter>
              <TableRow
                sx={{ bgcolor: alpha(theme.palette.primary.main, 0.07) }}
              >
                <TableCell colSpan={2}>
                  <Stack direction="row" spacing={1} alignItems="center">
                    <SummarizeIcon color="primary" fontSize="small" />
                    <Typography variant="subtitle2" fontWeight={600}>
                      สรุปรวมทั้งหมด ({fields.length} คน)
                    </Typography>
                  </Stack>
                </TableCell>
                <TableCell align="center">
                  <Typography variant="subtitle2" fontWeight={600}>
                    {formatCurrency(totalSummary.totalSalary)}
                  </Typography>
                </TableCell>
                <TableCell align="center">
                  <Typography variant="subtitle2" fontWeight={600}>
                    {formatCurrency(totalSummary.totalOvertime)}
                  </Typography>
                </TableCell>
                <TableCell align="center">
                  <Typography variant="subtitle2" fontWeight={600}>
                    {formatCurrency(totalSummary.totalAllowances)}
                  </Typography>
                </TableCell>
                <TableCell align="center">
                  <Typography variant="subtitle2" fontWeight={600}>
                    {formatCurrency(totalSummary.totalBonus)}
                  </Typography>
                </TableCell>
                <TableCell align="center">
                  <Typography variant="subtitle2" fontWeight={600}>
                    {formatCurrency(totalSummary.totalTax)}
                  </Typography>
                </TableCell>
                <TableCell align="center">
                  <Typography variant="subtitle2" fontWeight={600}>
                    {formatCurrency(totalSummary.totalSSO)}
                  </Typography>
                </TableCell>
                <TableCell align="center">
                  <Typography variant="subtitle2" fontWeight={600}>
                    {formatCurrency(totalSummary.totalOther)}
                  </Typography>
                </TableCell>
                <TableCell align="center">
                  <Paper
                    sx={{
                      p: 1,
                      bgcolor: alpha(theme.palette.success.main, 0.1),
                      borderColor: alpha(theme.palette.success.main, 0.3),
                      border: `1px solid ${alpha(
                        theme.palette.success.main,
                        0.3,
                      )}`,
                      borderRadius: 1,
                    }}
                  >
                    <Typography
                      variant="subtitle2"
                      fontWeight={700}
                      color="success.main"
                      textAlign="right"
                    >
                      {formatCurrency(totalSummary.totalNet)}
                    </Typography>
                  </Paper>
                </TableCell>
                <TableCell></TableCell>
              </TableRow>
            </TableFooter>
          </Table>
        </TableContainer>
      </Card>

      <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
        <Stack direction="row" spacing={1} alignItems="center">
          <Typography variant="body2" color="text.secondary">
            รวมพนักงาน {fields.length} คน, วันทำงานทั้งหมด{' '}
            {totalSummary.totalWorkDays} วัน
          </Typography>
        </Stack>
        <Stack direction="row" spacing={4} alignItems="center">
          <Stack direction="row" spacing={1} alignItems="center">
            <TrendingUpIcon color="primary" fontSize="small" />
            <Typography variant="body2" color="text.secondary">
              รายได้รวม:
            </Typography>
            <Typography variant="body2" fontWeight={600} color="primary.main">
              {formatCurrency(totalSummary.totalIncome)}
            </Typography>
          </Stack>
          <Stack direction="row" spacing={1} alignItems="center">
            <TrendingDownIcon color="error" fontSize="small" />
            <Typography variant="body2" color="text.secondary">
              หักรวม:
            </Typography>
            <Typography variant="body2" fontWeight={600} color="error.main">
              {formatCurrency(totalSummary.totalDeductions)}
            </Typography>
          </Stack>
          <Stack direction="row" spacing={1} alignItems="center">
            <MoneyIcon color="success" fontSize="small" />
            <Typography variant="body2" color="text.secondary">
              จ่ายสุทธิ:
            </Typography>
            <Typography variant="body2" fontWeight={700} color="success.main">
              {formatCurrency(totalSummary.totalNet)}
            </Typography>
          </Stack>
        </Stack>
      </Box>
    </Box>
  );
}
