import React from 'react';
import {
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Button,
  Stack,
  Chip,
  Box,
  Typography,
  Avatar,
  Card,
  CardContent,
  useTheme,
  alpha,
  Tooltip,
  IconButton,
} from '@mui/material';
import {
  AssignmentLate as AssignmentLateIcon,
  CheckCircle as ApproveIcon,
  Cancel as RejectIcon,
  Schedule as TimeIcon,
  Person as PersonIcon,
  Assignment as ProjectIcon,
  AccessTime as ClockIcon,
  CheckCircleOutline as StatusIcon,
} from '@mui/icons-material';
import dayjs from 'dayjs';
import { OT_STATUS } from 'utils/constants';

export default function OtCheckRe({ timestamp, renderApprove, renderReject }) {
  const theme = useTheme();
  const hasData = timestamp?.rows && timestamp.rows.length > 0;

  const calculateHours = (startTime, endTime) => {
    return dayjs(endTime).diff(dayjs(startTime), 'hour', true).toFixed(1);
  };

  const getStatusColor = (status) => {
    return OT_STATUS?.[status]?.color || 'default';
  };

  const getStatusLabel = (status) => {
    return OT_STATUS?.[status]?.status_code || status;
  };

  if (!hasData) {
    return (
      <Card variant="outlined" sx={{ borderRadius: 2 }}>
        <CardContent sx={{ py: 6, textAlign: 'center' }}>
          <AssignmentLateIcon
            sx={{ fontSize: 64, color: 'text.disabled', mb: 2 }}
          />
          <Typography variant="h6" color="text.secondary" gutterBottom>
            ไม่มีรายการรออนุมัติ
          </Typography>
          <Typography variant="body2" color="text.secondary">
            ไม่พบข้อมูลการขอ OT ที่รออนุมัติในขณะนี้
          </Typography>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card variant="outlined" sx={{ borderRadius: 2 }}>
      <TableContainer>
        <Table size="small" sx={{ minWidth: 800 }}>
          <TableHead>
            <TableRow sx={{ bgcolor: alpha(theme.palette.primary.main, 0.05) }}>
              <TableCell sx={{ fontWeight: 600, width: 60 }}>ลำดับ</TableCell>
              <TableCell sx={{ fontWeight: 600, minWidth: 200 }}>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <PersonIcon fontSize="small" />
                  <span>พนักงาน</span>
                </Stack>
              </TableCell>
              <TableCell sx={{ fontWeight: 600, minWidth: 180 }}>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <ProjectIcon fontSize="small" />
                  <span>โปรเจค</span>
                </Stack>
              </TableCell>
              <TableCell sx={{ fontWeight: 600, minWidth: 200 }}>
                รายละเอียด
              </TableCell>
              {/* เพิ่มขนาดช่องเวลา */}
              <TableCell sx={{ fontWeight: 600, minWidth: 180 }}>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <ClockIcon fontSize="small" />
                  <span>ช่วงเวลา</span>
                </Stack>
              </TableCell>
              <TableCell sx={{ fontWeight: 600, minWidth: 100 }}>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <TimeIcon fontSize="small" />
                  <span>ชั่วโมง</span>
                </Stack>
              </TableCell>
              {/* ลดขนาดช่องสถานะ */}
              <TableCell sx={{ fontWeight: 600, minWidth: 140 }}>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <StatusIcon fontSize="small" />
                  <span>สถานะ / ผู้อนุมัติ</span>
                </Stack>
              </TableCell>
              <TableCell align="center" sx={{ fontWeight: 600, minWidth: 120 }}>
                จัดการ
              </TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {timestamp.rows.map((row, index) => (
              <TableRow
                key={row.id}
                sx={{
                  '&:hover': {
                    bgcolor: alpha(theme.palette.primary.main, 0.02),
                  },
                }}
              >
                {/* ลำดับ */}
                <TableCell>
                  <Typography variant="body2" fontWeight={500}>
                    {index + 1}
                  </Typography>
                </TableCell>

                {/* พนักงาน */}
                <TableCell>
                  <Stack direction="row" spacing={2} alignItems="center">
                    <Box>
                      <Typography variant="body2" fontWeight={500}>
                        {row?.employee?.firstname} {row?.employee?.lastname}
                      </Typography>
                      <Typography variant="caption" color="text.secondary">
                        {row?.employee?.employeeId || 'N/A'}
                      </Typography>
                    </Box>
                  </Stack>
                </TableCell>

                {/* โปรเจค */}
                <TableCell>
                  <Box>
                    <Typography variant="body2" fontWeight={500}>
                      {row?.project?.project_number || 'N/A'}
                    </Typography>
                    <Typography variant="caption" color="text.secondary">
                      {row?.project?.name || 'ไม่ระบุโปรเจค'}
                    </Typography>
                  </Box>
                </TableCell>

                {/* รายละเอียด */}
                <TableCell>
                  <Tooltip title={row?.description || 'ไม่มีรายละเอียด'}>
                    <Typography
                      variant="body2"
                      sx={{
                        maxWidth: 200,
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                        whiteSpace: 'nowrap',
                      }}
                    >
                      {row?.description || 'ไม่มีรายละเอียด'}
                    </Typography>
                  </Tooltip>
                </TableCell>

                {/* ช่วงเวลา - ขยายขนาด */}
                <TableCell>
                  <Stack spacing={0.5}>
                    <Paper
                      variant="outlined"
                      sx={{
                        p: 1.5,
                        bgcolor: alpha(theme.palette.info.main, 0.05),
                        borderColor: alpha(theme.palette.info.main, 0.2),
                        borderRadius: 1,
                      }}
                    >
                      <Stack direction="row" alignItems="center" spacing={1}>
                        <ClockIcon fontSize="small" color="info" />
                        <Typography variant="body2" fontWeight={600}>
                          {dayjs(row?.startTime).format('HH:mm')} -{' '}
                          {dayjs(row?.endTime).format('HH:mm')}
                        </Typography>
                      </Stack>
                    </Paper>
                    <Typography
                      variant="caption"
                      color="text.secondary"
                      sx={{ textAlign: 'center' }}
                    >
                      {dayjs(row?.startTime).format('DD/MM/YYYY')}
                    </Typography>
                  </Stack>
                </TableCell>

                {/* จำนวนชั่วโมง */}
                <TableCell>
                  <Chip
                    label={`${calculateHours(
                      row?.startTime,
                      row?.endTime,
                    )} ชม.`}
                    size="small"
                    color="info"
                    variant="outlined"
                    sx={{ fontWeight: 500 }}
                  />
                </TableCell>

                {/* สถานะ / ผู้อนุมัติ - ลดขนาด */}
                <TableCell>
                  <Stack spacing={0.5}>
                    {/* สถานะ */}
                    <Chip
                      label={getStatusLabel(row?.status)}
                      color={getStatusColor(row?.status)}
                      size="small"
                      variant="filled"
                      sx={{ fontSize: '0.7rem' }}
                    />

                    {/* ผู้อนุมัติ */}
                    {row?.approver ? (
                      <Typography
                        variant="caption"
                        fontWeight={500}
                        sx={{
                          fontSize: '0.7rem',
                          overflow: 'hidden',
                          textOverflow: 'ellipsis',
                          whiteSpace: 'nowrap',
                          maxWidth: 120,
                        }}
                      >
                        {row?.approver?.firstname} {row?.approver?.lastname}
                      </Typography>
                    ) : (
                      <Typography
                        variant="caption"
                        color="text.secondary"
                        sx={{ fontSize: '0.7rem' }}
                      >
                        รออนุมัติ
                      </Typography>
                    )}
                  </Stack>
                </TableCell>

                {/* ปุ่มจัดการ */}
                <TableCell align="center">
                  {row?.status === 'PENDING' ? (
                    <Stack direction="row" spacing={1} justifyContent="center">
                      <Tooltip title="อนุมัติ">
                        <IconButton
                          color="success"
                          size="small"
                          onClick={() => renderApprove(row)}
                          sx={{
                            bgcolor: alpha(theme.palette.success.main, 0.1),
                            '&:hover': {
                              bgcolor: alpha(theme.palette.success.main, 0.2),
                            },
                          }}
                        >
                          <ApproveIcon fontSize="small" />
                        </IconButton>
                      </Tooltip>
                      <Tooltip title="ปฏิเสธ">
                        <IconButton
                          color="error"
                          size="small"
                          onClick={() => renderReject(row)}
                          sx={{
                            bgcolor: alpha(theme.palette.error.main, 0.1),
                            '&:hover': {
                              bgcolor: alpha(theme.palette.error.main, 0.2),
                            },
                          }}
                        >
                          <RejectIcon fontSize="small" />
                        </IconButton>
                      </Tooltip>
                    </Stack>
                  ) : (
                    <Typography variant="caption" color="text.secondary">
                      ดำเนินการแล้ว
                    </Typography>
                  )}
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </TableContainer>
    </Card>
  );
}
